class Solution(object):
    def countCells(self, grid, pattern):
        m, n = len(grid), len(grid[0])
        p = len(pattern)

        def kmp_search(text, pat):
            fail = [0] * len(pat)
            j = 0
            for i in range(1, len(pat)):
                while j > 0 and pat[i] != pat[j]:
                    j = fail[j-1]
                if pat[i] == pat[j]:
                    j += 1
                fail[i] = j
            positions = []
            j = 0
            for i, c in enumerate(text):
                while j > 0 and c != pat[j]:
                    j = fail[j-1]
                if c == pat[j]:
                    j += 1
                if j == len(pat):
                    positions.append(i - len(pat) + 1)
                    j = fail[j-1]
            return positions

        # Horizontal: row by row (no wrap from bottom row)
        h_str = ''.join(''.join(row) for row in grid)
        h_matches = kmp_search(h_str, pattern)
        h_covered = [[False]*n for _ in range(m)]
        for start in h_matches:
            for k in range(p):
                pos = start + k
                r, c = pos // n, pos % n
                if r < m:
                    h_covered[r][c] = True

        # Vertical: column by column (no wrap from last column)
        v_str = ''.join(grid[r][c] for c in range(n) for r in range(m))
        v_matches = kmp_search(v_str, pattern)
        v_covered = [[False]*n for _ in range(m)]
        for start in v_matches:
            for k in range(p):
                pos = start + k
                c, r = pos // m, pos % m
                if c < n:
                    v_covered[r][c] = True

        return sum(1 for r in range(m) for c in range(n) if h_covered[r][c] and v_covered[r][c])
